// 取得 AI 回傳（支援多種格式）
const aiOutput = $input.first().json;

// 直接從「準備 AI Prompt」節點取得最初的信件時間，不依賴 AI 判斷
// 取得原始時間
const rawDate = $('準備 AI Prompt').first().json.date;

// 使用 n8n 內建的 Luxon (DateTime) 轉換時區並輸出為 ISO 格式
const emailDate = DateTime.fromISO(rawDate).setZone('America/Chicago').toISO();

let parsed = null;
try {
  let rawContent = "";
  if (typeof aiOutput.text === 'string') {
    rawContent = aiOutput.text;
  } else if (typeof aiOutput.output === 'string') {
    rawContent = aiOutput.output;
  } else if (aiOutput.card_name || aiOutput.error) {
    parsed = aiOutput;
  } else {
    const firstVal = Object.values(aiOutput).find(v => typeof v === 'string' && (v.includes('{') || v.includes('}')));
    if (firstVal) {
      rawContent = firstVal;
    } else {
      throw new Error('找不到類似 JSON 的內容');
    }
  }

  // 如果還沒有轉成物件，進行解析並清理可能包含的 Markdown 標記
  if (!parsed && rawContent) {
    let cleanText = rawContent.replace(/```json/ig, '').replace(/```/g, '').trim();
    parsed = JSON.parse(cleanText);
  }
} catch (error) {
  // 抓取不正確的狀況 1：AI 回傳的格式完全壞掉，不是 JSON
  throw new Error('無法解析 AI 回傳的 JSON 格式：' + error.message + '\n原始內容：' + JSON.stringify(aiOutput));
}

// 狀況 2：明確辨識為不是付款確認信件 → 停止流程
// 在 n8n 中，Code 節點回傳空陣列 []，代表不會有任何資料傳遞到下一個節點，
// 流程會在這裡「安靜地結束」，不會被標記為錯誤。
if (parsed?.error === 'not_a_payment') {
  return []; 
}

// 抓取不正確的狀況 3：有缺漏必要欄位 -> 拋出錯誤 (會讓流程標記為 Failed)
const required = ['card_name', 'payment_amount'];
for (const field of required) {
  if (parsed[field] === undefined || parsed[field] === null || parsed[field] === '') {
    throw new Error(`AI 抓取錯誤，缺少必要欄位：${field}。\n目前抓到：${JSON.stringify(parsed)}`);
  }
}

// 抓取不正確的狀況 4：信用卡名稱不在白名單中 -> 拋出錯誤
const validCards = [
  'Chase Unlimited Freedom',
  'Customized Cash Reward',
  'CITI StrataSM',
  'Apple Card'
];
if (!validCards.includes(parsed.card_name)) {
  throw new Error(`AI 抓取錯誤，card_name (${parsed.card_name}) 不在系統白名單中。`);
}

// 抓取不正確的狀況 5：金額不是有效數字 -> 拋出錯誤
// 確保移除可能的貨幣符號或逗號
let cleanAmountStr = String(parsed.payment_amount).replace(/[$,]/g, '');
const amount = parseFloat(cleanAmountStr);
if (isNaN(amount) || amount <= 0) {
  throw new Error(`AI 抓取錯誤，金額無效：${parsed.payment_amount}`);
}

// 成功抓取，將資料傳遞給下一個節點
return [{ json: {
  targetAccount: parsed.card_name,
  balance: amount,
  paymentDate: emailDate,
  source: 'Chase 銀行'
} }];

