const body = {
  jsonrpc: '2.0',
  method: 'tools/call',
  params: {
    name: 'add_transaction',
    arguments: {
      type: 'transfer',
      time: $json.paymentDate,
      amount: String($json.balance),
      destination_amount: String($json.balance),
      category_name: '信用卡還款',
      account_name: $json.source,
      destination_account_name: $json.targetAccount,
      tags: ['Settle'],
      comment: '自動還款 - ' + $json.targetAccount
    }
  },
  id: 3
};

return [{ json: { ...$json, mcpBody: body } }];
